# Targeted search for phrases in Quran and hadith
def find_phrase_in_db(phrase):
    norm_p = normalize_ar(phrase)
    # search quran
    res_q = []
    for t, l, nt in zip(q_texts, q_labels, norm_q_texts):
        if norm_p in nt:
            res_q.append((l, t))
    # search hadith
    res_h = []
    for t, l, nt in zip(h_texts, h_labels, norm_h_texts):
        if norm_p in nt:
            res_h.append((l, t))
    return res_q, res_h

phrases = ["الله وحده يعلم", "كم عانى", "كم تحمل", "لينقذنا", "من الظلام"]
results = {p: find_phrase_in_db(p) for p in phrases}
{k: (len(v[0]), len(v[1])) for k,v in results.items()}
